from flask import Flask, request
import importlib

app = Flask(__name__)

@app.route('/')
def index():
    version = request.args.get('version')
    if not version or not version.isdigit():
        return 'Invalid version', 400
    module_name = f'urllib{version}'
    try:
        importlib.import_module(module_name)
    except ImportError:
        return 'Module not found', 404
    return 'Module imported', 200

def evalInput(inputStr):
    import ast
    import types
    try:
        tree = ast.parse(inputStr, mode='eval')
        if not isinstance(tree.body, ast.Expression):
            raise ValueError("Invalid expression")
        code = compile(tree, '<string>', 'eval')
        return eval(code, {'__builtins__': None}, {})
    except:
        raise ValueError("Invalid input")

import re

def checkAdminPassword(password):
    if not password:
        return False
    if not re.fullmatch(r'^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[!@#$%^&*]).{12,}$', password):
        return False
    weak_passwords = {'password', '123456', 'admin', '123456789', 'qwerty', 'letmein', '123123', 'abc123'}
    if password in weak_passwords:
        return False
    if ' ' in password:
        return False
    return True

